mapper.select:
/* oms-po-poCnfrm-sql-oracle.xml - selectTOrderPoCnfrmHd */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT '0' CHK , T.OWKEY , T.CTKEY , T.REQORDERDAY , T.REQORDERSTATUS , (SELECT COMDTNM FROM TORDER_MST_COM_DT DT WHERE DT.OWKEY = T.OWKEY AND DT.COMHDKEY = 'POSTATUS' AND DT.INSERTSYSTM = 'OMS' AND DT.COMDTKEY = T.REQORDERSTATUS AND DT.LAKEY = 'KOR') AS REQORDERSTATUSNM , T.REQORDERTYPE , (SELECT COMDTNM FROM TORDER_MST_COM_DT DT WHERE DT.OWKEY = T.OWKEY AND DT.COMHDKEY = 'REQORDERTYPE' AND DT.INSERTSYSTM = 'OMS' AND DT.COMDTKEY = T.REQORDERTYPE AND DT.LAKEY = 'KOR') AS REQORDERTYPENM , COALESCE(T.REQORDERNO, TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDDHH24MISS')|| LPAD(ROW_NUMBER() OVER(PARTITION BY T.OWKEY, T.CTKEY, T.REQORDERDAY, T.REQORDERSTATUS, T.URGENCYREQORDERYN ORDER BY T.OWKEY, T.CTKEY, T.REQORDERDAY, T.REQORDERSTATUS, T.URGENCYREQORDERYN)::TEXT, 3, '0')) AS REQORDERNO , T.URGENCYREQORDERYN , COALESCE(T.IBEXPCTDAY, TO_CHAR( CURRENT_TIMESTAMP + COALESCE(T.CTLEADTIME, 0) ,'YYYYMMDD' )) IBEXPCTDAY , CASE WHEN T.URGENCYREQORDERYN = 'Y' THEN '긴급' ELSE '정기' END AS URGENCYREQORDERYNNM , T.REQCTKEY AS REQCTKEY , T.REQCTNM AS REQCTNM , T.PLTYN , COUNT(ICKEY) AS SKU , SUM(T.REQORDERQTY) AS REQORDERQTY , TRUNC(SUM(T.REQORDERQTY / NULLIF(ICINN, 0)), 2) AS REQORDERINN , TRUNC(SUM(T.REQORDERQTY / NULLIF(ICCTN, 0)), 2) AS REQORDERCTN , TRUNC(SUM(T.REQORDERQTY / NULLIF(ICCTN, 0) / NULLIF(ICCPP, 0)), 2) AS REQORDERPLT , TRUNC(SUM(T.REQORDERQTY * COALESCE(T.SLPRC, 0)), 2) AS SLPRC , TRUNC(SUM(T.REQORDERQTY / T.ICINN * T.VOL), 2) AS VOL , MAX(T.INSERTDATE) AS INSERTDATE , MAX(T.INSERTURKEY) AS INSERTURKEY , MAX(T.UPDATEDATE) AS UPDATEDATE , MAX(T.UPDATEURKEY) AS UPDATEURKEY FROM ( SELECT RE.OWKEY , RE.CTKEY , RE.REQORDERDAY , RE.REQORDERSTATUS , RE.REQORDERTYPE , RE.URGENCYREQORDERYN , RE.REQORDERNO , RE.REQCTKEY , CT.CTNM AS REQCTNM , RE.ICKEY , RE.IBEXPCTDAY , CT.CTLEADTIME , SUM(RE.REQORDERQTY) AS REQORDERQTY , SUM(IC_INN) AS ICINN , SUM(IC_CTN) AS ICCTN , COALESCE(MAX(CASE WHEN REQCTKEY = '01' THEN NAMSACPP WHEN REQCTKEY = '04' THEN BUSANCPP WHEN REQCTKEY = '05' THEN ANSUNGCPP ELSE IC_CPP END), 1) AS ICCPP , SUM(I.SLPRC) AS SLPRC , SUM(ICUT.VOL) AS VOL , MAX(RE.INSERTDATE) AS INSERTDATE , MAX(RE.INSERTURKEY) AS INSERTURKEY , MAX(RE.UPDATEDATE) AS UPDATEDATE , MAX(RE.UPDATEURKEY) AS UPDATEURKEY , CASE WHEN RE.REQORDERTYPE ='03' AND RE.DLVYREQORDERUNIT ='PLT' THEN 'Y' ELSE 'N' END AS PLTYN FROM TORDER_INFO_REQORDER RE INNER JOIN TORDER_MST_CT CT ON RE.REQCTKEY = CT.CTKEY INNER JOIN TORDER_MST_IC I ON RE.OWKEY = I.OWKEY AND RE.ICKEY = I.ICKEY INNER JOIN TORDER_MST_ICUTXTYPE ICUT ON RE.OWKEY = ICUT.OWKEY AND RE.ICKEY = ICUT.ICKEY AND ICUT.ICUNITTYPE = 'INN' INNER JOIN TORDER_MST_ICXCT IC ON RE.OWKEY = IC.OWKEY AND RE.ICKEY = IC.ICKEY AND RE.CTKEY = IC.CTKEY INNER JOIN ( SELECT ICKEY , OWKEY , COALESCE(SUM(CASE WHEN ICUNITTYPE = 'EA' THEN ICUNITQTY END), 1) AS IC_EA , COALESCE(SUM(CASE WHEN ICUNITTYPE = 'INN' THEN ICUNITQTY END), 1) AS IC_INN , COALESCE(SUM(CASE WHEN ICUNITTYPE = 'CTN' THEN ICUNITQTY END), 1) AS IC_CTN , COALESCE(SUM(CASE WHEN ICUNITTYPE = 'CTN' THEN CASE CPP WHEN 0 THEN 1 ELSE CPP END END), 1) AS IC_CPP FROM TORDER_MST_ICUTXTYPE WHERE OWKEY = 'DAISO' GROUP BY ICKEY, OWKEY ) S_ICUT ON I.OWKEY = S_ICUT.OWKEY AND I.ICKEY = S_ICUT.ICKEY LEFT JOIN ( SELECT A.ICKEY , COALESCE(MAX(CASE WHEN A.CTKEY = '01' THEN CPP END), 1) AS NAMSACPP , COALESCE(MAX(CASE WHEN A.CTKEY = '04' THEN CPP END), 1) AS BUSANCPP , COALESCE(MAX(CASE WHEN A.CTKEY = '05' THEN CPP END), 1) AS ANSUNGCPP FROM TORDER_MST_ICXB2BCPP A GROUP BY A.ICKEY )CTCPP ON IC.ICKEY = CTCPP.ICKEY WHERE RE.REQORDERSTATUS IN ('01','02')
AND #{SEARCH_CONDITION}
AND RE.ICKEY IN
#{item}
GROUP BY RE.OWKEY , RE.CTKEY , RE.REQORDERNO , RE.REQORDERDAY , RE.REQORDERSTATUS , RE.REQORDERTYPE , RE.URGENCYREQORDERYN , RE.REQCTKEY , CT.CTNM , RE.ICKEY , RE.IBEXPCTDAY , CT.CTLEADTIME , CASE WHEN RE.REQORDERTYPE ='03' AND RE.DLVYREQORDERUNIT ='PLT' THEN 'Y' ELSE 'N' END ) T GROUP BY T.OWKEY , T.CTKEY , T.REQORDERDAY , T.REQORDERSTATUS , T.REQORDERTYPE , T.URGENCYREQORDERYN , T.REQORDERNO , T.REQCTKEY , T.REQCTNM , T.PLTYN , COALESCE(T.IBEXPCTDAY, TO_CHAR( CURRENT_TIMESTAMP + COALESCE(T.CTLEADTIME, 0) ,'YYYYMMDD' ))
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY MAX(T.UPDATEDATE) DESC NULLS LAST, T.REQORDERNO ASC
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

/* oms-po-poCnfrm-sql-oracle.xml - selectTOrderPoCnfrmHdCount */ SELECT COUNT(*) FROM ( SELECT RE.OWKEY , RE.CTKEY , RE.REQORDERDAY , RE.REQORDERSTATUS , COALESCE(RE.REQORDERNO, TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDDHH24MISS')|| LPAD(ROW_NUMBER() OVER(PARTITION BY RE.OWKEY, RE.CTKEY, RE.REQORDERDAY, RE.REQORDERSTATUS ORDER BY RE.OWKEY)::TEXT, 3, '0')) AS REQORDERNO , RE.REQCTKEY , CT.CTNM AS REQCTNM , COUNT(RE.ICKEY) AS SKU , SUM(RE.REQORDERQTY) AS REQORDERQTY , ROUND(SUM(RE.REQORDERQTY) / NULLIF(MAX(IC_INN), 0), 2) AS REQORDERINN , ROUND(SUM(RE.REQORDERQTY) / NULLIF(MAX(IC_CTN), 0), 2) AS REQORDERCTN , ROUND( SUM(RE.REQORDERQTY)/ NULLIF(MAX(IC_CTN), 0)/ NULLIF(MAX(IC_CPP), 0), 2) AS REQORDERPLT , ROUND(AVG(I.SLPRC), 5) AS SLPRC , ROUND(AVG(ICUT.VOL), 5) AS VOL , MAX(RE.INSERTDATE) AS INSERTDATE , MAX(RE.INSERTURKEY) AS INSERTURKEY , MAX(RE.UPDATEDATE) AS UPDATEDATE , MAX(RE.UPDATEURKEY) AS UPDATEURKEY FROM TORDER_INFO_REQORDER RE INNER JOIN TORDER_MST_CT CT ON RE.REQCTKEY = CT.CTKEY INNER JOIN TORDER_MST_IC I ON RE.OWKEY = I.OWKEY AND RE.ICKEY = I.ICKEY INNER JOIN TORDER_MST_ICUTXTYPE ICUT ON RE.OWKEY = ICUT.OWKEY AND RE.ICKEY = ICUT.ICKEY AND ICUT.ICUNITTYPE = 'EA' INNER JOIN TORDER_MST_ICXCT IC ON RE.OWKEY = IC.OWKEY AND RE.ICKEY = IC.ICKEY AND RE.CTKEY = IC.CTKEY INNER JOIN ( SELECT ICKEY , OWKEY , COALESCE(SUM(CASE WHEN ICUNITTYPE = 'EA' THEN ICUNITQTY END), 1) AS IC_EA , COALESCE(SUM(CASE WHEN ICUNITTYPE = 'INN' THEN ICUNITQTY END), 1) AS IC_INN , COALESCE(SUM(CASE WHEN ICUNITTYPE = 'CTN' THEN ICUNITQTY END), 1) AS IC_CTN , COALESCE(SUM(CASE WHEN ICUNITTYPE = 'CTN' THEN CASE CPP WHEN 0 THEN 1 ELSE CPP END END), 1) AS IC_CPP FROM TORDER_MST_ICUTXTYPE WHERE OWKEY = #{owkey} GROUP BY ICKEY, OWKEY ) S_ICUT ON I.OWKEY = S_ICUT.OWKEY AND I.ICKEY = S_ICUT.ICKEY WHERE RE.REQORDERSTATUS IN ('01','02') --AND RE.REQORDERTYPE IN ('03')
AND #{SEARCH_CONDITION}
AND RE.ICKEY IN
#{item}
GROUP BY RE.OWKEY , RE.CTKEY , RE.REQORDERDAY , RE.REQORDERSTATUS , RE.REQORDERNO , RE.REQCTKEY , CT.CTNM , CASE RE.DLVYREQORDERUNIT WHEN 'PLT' THEN 'Y' ELSE 'N' END ) T

/* oms-po-poCnfrm-sql-oracle.xml - selectTOrderPoCnfrmDt */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT '0' AS CHK , RE.REQORDERSTATUS , Y.COMDTNM AS REQORDERSTATUSNM , RE.UPLOADYN , RE.REQORDERTYPE , Z.COMDTNM AS REQORDERTYPENM , RE.ICKEY , IC.ICNM , IC.ASRTYN , RE.REQORDERAR , RE.ICTGT , RE.AVQTY , RE.IBEXPCTQTY AS B2CIBQTY , RE.AVQTY + RE.IBEXPCTQTY AS TOTQTY , RE.CALAVDAYS -- 환산가용일 , ROUND(COALESCE(RE.AVGOBQTY, 0), 2) AS EADAYAVGOBQTY , ROUND(COALESCE(RE.AVGOBQTY, 0) / NULLIF(UT.IC_INN,0), 2) AS INNDAYAVGOBQTY , ROUND(COALESCE(RE.AVGOBQTY, 0) / NULLIF(UT.IC_CTN,0), 2) AS CTNDAYAVGOBQTY , CASE RE.REQCTKEY WHEN '05' THEN ROUND(COALESCE(RE.AVGOBQTY, 0) / NULLIF(UT.IC_CTN,0) / NULLIF(CPP05,0), 2) WHEN '04' THEN ROUND(COALESCE(RE.AVGOBQTY, 0) / NULLIF(UT.IC_CTN,0) / NULLIF(CPP04,0), 2) WHEN '01' THEN ROUND(COALESCE(RE.AVGOBQTY, 0) / NULLIF(UT.IC_CTN,0) / NULLIF(CPP01,0), 2) ELSE 0 END AS PLTDAYAVGOBQTY , RE.REQCTKEY , CT.CTNM AS REQCTNM , RE.CTLEADTIME , RE.AVDAYS -- 발주 필요 가능일 : (가용일 + 센터 리드타임) - 현재 환산 가용일 [현재 환산가용일 : 총재고 / 일평균수량] , RE.AVDAYS + RE.CTLEADTIME - RE.CALAVDAYS AS PONEEDDAYS , ROUND( (RE.AVDAYS + RE.CTLEADTIME - RE.CALAVDAYS) * COALESCE(RE.AVGOBQTY, 0), 2) AS PONEEDQTYEA , ROUND( COALESCE((RE.AVDAYS + RE.CTLEADTIME - RE.CALAVDAYS) * RE.AVGOBQTY / NULLIF(UT.IC_INN,0), 0), 2) AS PONEEDQTYINN , ROUND( COALESCE((RE.AVDAYS + RE.CTLEADTIME - RE.CALAVDAYS) * RE.AVGOBQTY / NULLIF(UT.IC_CTN,0), 0), 2) AS PONEEDQTYCTN , COALESCE(CASE WHEN RE.REQCTKEY='05' THEN ROUND((RE.AVDAYS + RE.CTLEADTIME - RE.CALAVDAYS)*RE.AVGOBQTY/NULLIF(UT.IC_CTN,0)/NULLIF(CPP05,0), 2) WHEN RE.REQCTKEY='04' THEN ROUND((RE.AVDAYS + RE.CTLEADTIME - RE.CALAVDAYS)*RE.AVGOBQTY/NULLIF(UT.IC_CTN,0)/NULLIF(CPP04,0), 2) WHEN RE.REQCTKEY='01' THEN ROUND((RE.AVDAYS + RE.CTLEADTIME - RE.CALAVDAYS)*RE.AVGOBQTY/NULLIF(UT.IC_CTN,0)/NULLIF(CPP01,0), 2) ELSE 0 END, 0) AS PONEEDQTYPLT
-- 센터재고 반영 필요 발주량 : 필요발주량 – (B2B재고수량 – (보장재고일수 * 오프라인일 평균수량 )) , ROUND( CASE WHEN (CASE WHEN RE.REQCTKEY='05' THEN COALESCE(B2BINFO.IBEXPCTQTY05 + B2BINFO.AVQTY05, 0) - COALESCE(B2BCON.GRTIVDAYS05 * B2BINFO.AVGOBQTY05, 0) WHEN RE.REQCTKEY='04' THEN COALESCE(B2BINFO.IBEXPCTQTY04 + B2BINFO.AVQTY04, 0) - COALESCE(B2BCON.GRTIVDAYS04 * B2BINFO.AVGOBQTY04, 0) WHEN RE.REQCTKEY='01' THEN COALESCE(B2BINFO.IBEXPCTQTY01 + B2BINFO.AVQTY01, 0) - COALESCE(B2BCON.GRTIVDAYS01 * B2BINFO.AVGOBQTY01, 0) ELSE 0 END) <= 0 THEN 0 ELSE LEAST( GREATEST(0, COALESCE(RE.AVDAYS + RE.CTLEADTIME - RE.CALAVDAYS, 0) * COALESCE(RE.AVGOBQTY, 0)), CASE WHEN RE.REQCTKEY='05' THEN COALESCE(B2BINFO.IBEXPCTQTY05 + B2BINFO.AVQTY05, 0) - COALESCE(B2BCON.GRTIVDAYS05 * B2BINFO.AVGOBQTY05, 0) WHEN RE.REQCTKEY='04' THEN COALESCE(B2BINFO.IBEXPCTQTY04 + B2BINFO.AVQTY04, 0) - COALESCE(B2BCON.GRTIVDAYS04 * B2BINFO.AVGOBQTY04, 0) WHEN RE.REQCTKEY='01' THEN COALESCE(B2BINFO.IBEXPCTQTY01 + B2BINFO.AVQTY01, 0) - COALESCE(B2BCON.GRTIVDAYS01 * B2BINFO.AVGOBQTY01, 0) ELSE 0 END) END , 2) IVRFLCTNEEDQTYEA
, ROUND( CASE WHEN CASE WHEN RE.REQCTKEY = '05' THEN COALESCE(B2BINFO.IBEXPCTQTY05 + B2BINFO.AVQTY05, 0) - COALESCE(B2BCON.GRTIVDAYS05 * B2BINFO.AVGOBQTY05, 0) WHEN RE.REQCTKEY = '04' THEN COALESCE(B2BINFO.IBEXPCTQTY04 + B2BINFO.AVQTY04, 0) - COALESCE(B2BCON.GRTIVDAYS04 * B2BINFO.AVGOBQTY04, 0) WHEN RE.REQCTKEY = '01' THEN COALESCE(B2BINFO.IBEXPCTQTY01 + B2BINFO.AVQTY01, 0) - COALESCE(B2BCON.GRTIVDAYS01 * B2BINFO.AVGOBQTY01, 0) ELSE 0 END <= 0 THEN 0 ELSE LEAST( /* 필요발주량 = (가용일+리드타임-환산가용일)*일평균 */ GREATEST(0, COALESCE(RE.AVDAYS + RE.CTLEADTIME - RE.CALAVDAYS, 0) * COALESCE(RE.AVGOBQTY, 0)), /* 센터별 가용재고-보장재고 */ CASE WHEN RE.REQCTKEY = '05' THEN COALESCE(B2BINFO.IBEXPCTQTY05 + B2BINFO.AVQTY05, 0) - COALESCE(B2BCON.GRTIVDAYS05 * B2BINFO.AVGOBQTY05, 0) WHEN RE.REQCTKEY = '04' THEN COALESCE(B2BINFO.IBEXPCTQTY04 + B2BINFO.AVQTY04, 0) - COALESCE(B2BCON.GRTIVDAYS04 * B2BINFO.AVGOBQTY04, 0) WHEN RE.REQCTKEY = '01' THEN COALESCE(B2BINFO.IBEXPCTQTY01 + B2BINFO.AVQTY01, 0) - COALESCE(B2BCON.GRTIVDAYS01 * B2BINFO.AVGOBQTY01, 0) ELSE 0 END ) END / NULLIF(UT.IC_INN, 0) , 2) AS IVRFLCTNEEDQTYINN
, ROUND( CASE WHEN CASE WHEN RE.REQCTKEY = '05' THEN COALESCE(B2BINFO.IBEXPCTQTY05 + B2BINFO.AVQTY05, 0) - COALESCE(B2BCON.GRTIVDAYS05 * B2BINFO.AVGOBQTY05, 0) WHEN RE.REQCTKEY = '04' THEN COALESCE(B2BINFO.IBEXPCTQTY04 + B2BINFO.AVQTY04, 0) - COALESCE(B2BCON.GRTIVDAYS04 * B2BINFO.AVGOBQTY04, 0) WHEN RE.REQCTKEY = '01' THEN COALESCE(B2BINFO.IBEXPCTQTY01 + B2BINFO.AVQTY01, 0) - COALESCE(B2BCON.GRTIVDAYS01 * B2BINFO.AVGOBQTY01, 0) ELSE 0 END <= 0 THEN 0 ELSE LEAST( /* 필요발주량(EA) = (가용일 + 리드타임 - 환산가용일) * 일평균 */ GREATEST(0, COALESCE(RE.AVDAYS + RE.CTLEADTIME - RE.CALAVDAYS, 0) * COALESCE(RE.AVGOBQTY, 0)), /* 센터별 (가용+입고예정) - (보장일수*일평균) */ CASE WHEN RE.REQCTKEY = '05' THEN COALESCE(B2BINFO.IBEXPCTQTY05 + B2BINFO.AVQTY05, 0) - COALESCE(B2BCON.GRTIVDAYS05 * B2BINFO.AVGOBQTY05, 0) WHEN RE.REQCTKEY = '04' THEN COALESCE(B2BINFO.IBEXPCTQTY04 + B2BINFO.AVQTY04, 0) - COALESCE(B2BCON.GRTIVDAYS04 * B2BINFO.AVGOBQTY04, 0) WHEN RE.REQCTKEY = '01' THEN COALESCE(B2BINFO.IBEXPCTQTY01 + B2BINFO.AVQTY01, 0) - COALESCE(B2BCON.GRTIVDAYS01 * B2BINFO.AVGOBQTY01, 0) ELSE 0 END ) END / NULLIF(UT.IC_CTN, 0) , 2) AS IVRFLCTNEEDQTYCTN
, ROUND( CASE WHEN CASE WHEN RE.REQCTKEY = '05' THEN COALESCE(B2BINFO.IBEXPCTQTY05 + B2BINFO.AVQTY05, 0) - COALESCE(B2BCON.GRTIVDAYS05 * B2BINFO.AVGOBQTY05, 0) WHEN RE.REQCTKEY = '04' THEN COALESCE(B2BINFO.IBEXPCTQTY04 + B2BINFO.AVQTY04, 0) - COALESCE(B2BCON.GRTIVDAYS04 * B2BINFO.AVGOBQTY04, 0) WHEN RE.REQCTKEY = '01' THEN COALESCE(B2BINFO.IBEXPCTQTY01 + B2BINFO.AVQTY01, 0) - COALESCE(B2BCON.GRTIVDAYS01 * B2BINFO.AVGOBQTY01, 0) ELSE 0 END <= 0 THEN 0 ELSE LEAST( /* 필요발주량(EA) */ GREATEST(0, COALESCE(RE.AVDAYS + RE.CTLEADTIME - RE.CALAVDAYS, 0) * COALESCE(RE.AVGOBQTY, 0)), /* 센터별 (가용+입고예정) - (보장일수*일평균) */ CASE WHEN RE.REQCTKEY = '05' THEN COALESCE(B2BINFO.IBEXPCTQTY05 + B2BINFO.AVQTY05, 0) - COALESCE(B2BCON.GRTIVDAYS05 * B2BINFO.AVGOBQTY05, 0) WHEN RE.REQCTKEY = '04' THEN COALESCE(B2BINFO.IBEXPCTQTY04 + B2BINFO.AVQTY04, 0) - COALESCE(B2BCON.GRTIVDAYS04 * B2BINFO.AVGOBQTY04, 0) WHEN RE.REQCTKEY = '01' THEN COALESCE(B2BINFO.IBEXPCTQTY01 + B2BINFO.AVQTY01, 0) - COALESCE(B2BCON.GRTIVDAYS01 * B2BINFO.AVGOBQTY01, 0) ELSE 0 END ) END / NULLIF( COALESCE(UT.IC_CTN, 1) * COALESCE(CASE RE.REQCTKEY WHEN '01' THEN B2BCPP.CPP01 -- 남사 WHEN '04' THEN B2BCPP.CPP04 -- 부산 WHEN '05' THEN B2BCPP.CPP05 -- 안성 ELSE 1 END, 1) , 0) , 2) AS IVRFLCTNEEDQTYPLT , RE.REQORDERUNIT , RE.REQORDERQTY , RE.REQORDERQTY AS TEMPEA , COALESCE(ROUND( COALESCE(RE.REQORDERQTY, 0) / NULLIF(UT.IC_INN, 0), 2), 0) AS REQORDERINN , COALESCE(ROUND( COALESCE(RE.REQORDERQTY, 0) / NULLIF(UT.IC_CTN, 0), 2), 0) AS REQORDERCTN , CASE RE.REQCTKEY WHEN '05' THEN COALESCE(ROUND( COALESCE(RE.REQORDERQTY, 0) / NULLIF( UT.IC_CTN * (CASE WHEN B2BCPP.CPP05 = 0 THEN 1 ELSE B2BCPP.CPP05 END), 0 ) , 2), 0) WHEN '04' THEN COALESCE(ROUND( COALESCE(RE.REQORDERQTY, 0) / NULLIF( UT.IC_CTN * (CASE WHEN B2BCPP.CPP04 = 0 THEN 1 ELSE B2BCPP.CPP04 END), 0 ) , 2), 0) WHEN '01' THEN COALESCE(ROUND( COALESCE(RE.REQORDERQTY, 0) / NULLIF( UT.IC_CTN * (CASE WHEN B2BCPP.CPP01 = 0 THEN 1 ELSE B2BCPP.CPP01 END), 0 ) , 2), 0) ELSE 0 END AS REQORDERPLT , RE.DLVYREQORDERUNIT , MD.REQQTY AS MDREQQTY , MD.REQQTY - REQORDERQTY AS CALCQTY , MD.CMT AS MDCMT , UT.VOL * (REQORDERQTY / UT.IC_INN) AS REQCBM , COALESCE(IC.SLPRC, 0) * REQORDERQTY AS REQPRC /* 예정가용일: (현 재고 - 일평균*리드타임 + 발주요청수량) / 일평균 */ , CEIL( ( COALESCE(RE.AVQTY + RE.IBEXPCTQTY, 0) - CASE COALESCE(RE.AVGOBQTY, 0) WHEN 0 THEN 1 ELSE RE.AVGOBQTY END * COALESCE(RE.CTLEADTIME, 0) + RE.REQORDERQTY ) / CASE COALESCE(RE.AVGOBQTY, 0) WHEN 0 THEN 1 ELSE RE.AVGOBQTY END) AS EXPCTAVDAYS
, IC.UNICYN , IC.DSPYN , IC.DLVRYYN , IC.SALESTATUS , IC.POABLEYN AS ABLEREQORDERYN , ROUND(COALESCE(ST.MONTHQTY, 0), 2) AS EAMONTHAVGOBQTY , ROUND(COALESCE(ST.MONTHQTY, 0) / NULLIF(UT.IC_INN,0), 2) AS INNMONTHAVGOBQTY , ROUND(COALESCE(ST.MONTHQTY, 0) / NULLIF(UT.IC_CTN,0), 2) AS CTNMONTHAVGOBQTY , COALESCE(CASE RE.REQCTKEY WHEN '05' THEN ROUND(ST.MONTHQTY/NULLIF(UT.IC_CTN,0)/NULLIF(B2BCPP.CPP05,0), 2) WHEN '04' THEN ROUND(ST.MONTHQTY/NULLIF(UT.IC_CTN,0)/NULLIF(B2BCPP.CPP04,0), 2) WHEN '01' THEN ROUND(ST.MONTHQTY/NULLIF(UT.IC_CTN,0)/NULLIF(B2BCPP.CPP01,0), 2) ELSE 0 END, 0) PLTCTNMONTHAVGOBQTY , B2BINFO.AVQTY05 AS ANSUNGAVQTY , B2BINFO.AVQTY04 AS BUSANAVQTY , B2BINFO.AVQTY01 AS NAMSAAVQTY , B2BINFO.AVGOBQTY05 AS ANSUNGAVGOBQTY , B2BINFO.AVGOBQTY04 AS BUSANAVGOBQTY , B2BINFO.AVGOBQTY01 AS NAMSAAVGOBQTY , B2BINFO.AVGOBQTY05 * B2BCON.GRTIVDAYS05 AS ANSUNGB2BCTGRTQTY , B2BINFO.AVGOBQTY04 * B2BCON.GRTIVDAYS04 AS BUSANB2BCTGRTQTY , B2BINFO.AVGOBQTY01 * B2BCON.GRTIVDAYS01 AS NAMSAB2BCTGRTQTY , RE.REQORDERDAY , RE.URGENCYREQORDERYN , RE.REQORDEREXCEPTYN , RE.SEQ , RE.OWKEY , RE.CTKEY , B2BCPP.CPP05 AS ANSUNGCPP , B2BCPP.CPP04 AS BUSANCPP , B2BCPP.CPP01 AS NAMSACPP , CRITSET.CTNCRIT , CRITSET.PLTCRIT , CRITSET.INNCRIT , UT.IC_INN AS ICINN , UT.IC_CTN AS ICCTN , UT.IC_CPP AS ICCPP , RE.INSERTDATE , RE.INSERTURKEY , RE.UPDATEDATE , RE.UPDATEURKEY , IC.SLPRC , UT.VOL , ROUND((UT.VOL * RE.REQORDERQTY) / NULLIF(LC.CBMCLOSRNG, 0) * 100, 2) AS CBMRATE , LC.CBMCLOSRNG FROM TORDER_INFO_REQORDER RE INNER JOIN TORDER_MST_CT CT ON CT.CTKEY = RE.REQCTKEY INNER JOIN TORDER_MST_IC IC ON RE.OWKEY = IC.OWKEY AND RE.ICKEY = IC.ICKEY INNER JOIN ( SELECT OWKEY ,COMDTKEY , COMDTNM FROM TORDER_MST_COM_DT WHERE OWKEY =#{owkey} AND COMHDKEY ='POSTATUS' AND INSERTSYSTM = 'OMS' AND LAKEY = 'KOR' ) Y ON Y.OWKEY = RE.OWKEY AND Y.COMDTKEY = RE.REQORDERSTATUS INNER JOIN ( SELECT OWKEY ,COMDTKEY , COMDTNM FROM TORDER_MST_COM_DT WHERE OWKEY =#{owkey} AND COMHDKEY ='REQORDERTYPE' AND INSERTSYSTM = 'OMS' AND LAKEY = 'KOR' ) Z ON RE.OWKEY = Z.OWKEY AND Z.COMDTKEY = RE.REQORDERTYPE INNER JOIN ( SELECT OWKEY , ICKEY , COALESCE(SUM(CASE WHEN ICUNITTYPE = 'EA' THEN ICUNITQTY END), 1) AS IC_EA , COALESCE(SUM(CASE WHEN ICUNITTYPE = 'INN' THEN ICUNITQTY END), 1) AS IC_INN , COALESCE(SUM(CASE WHEN ICUNITTYPE = 'CTN' THEN ICUNITQTY END), 1) AS IC_CTN , COALESCE(SUM(CASE WHEN ICUNITTYPE = 'CTN' THEN CASE CPP WHEN 0 THEN 1 ELSE CPP END END), 1) AS IC_CPP , COALESCE(SUM(CASE WHEN ICUNITTYPE = 'INN' THEN VOL END), 1) AS VOL FROM TORDER_MST_ICUTXTYPE WHERE OWKEY = #{owkey}
GROUP BY OWKEY, ICKEY ) UT ON IC.OWKEY = UT.OWKEY AND IC.ICKEY = UT.ICKEY LEFT JOIN ( SELECT A.ICKEY , COALESCE(MAX(CASE WHEN A.CTKEY = '01' THEN CPP END), 1) AS CPP01 , COALESCE(MAX(CASE WHEN A.CTKEY = '04' THEN CPP END), 1) AS CPP04 , COALESCE(MAX(CASE WHEN A.CTKEY = '05' THEN CPP END), 1) AS CPP05 FROM TORDER_MST_ICXB2BCPP A GROUP BY A.ICKEY ) B2BCPP ON IC.ICKEY = B2BCPP.ICKEY LEFT JOIN TORDER_INFO_MD_RDEQODRDER MD ON RE.OWKEY = MD.OWKEY AND RE.CTKEY = MD.CTKEY AND RE.ICKEY = MD.ICKEY AND RE.REQORDERDAY = MD.REQORDERDAY LEFT JOIN ( SELECT OWKEY, CTKEY, ICKEY , DATE_TRUNC('day', SUM(QTY) / 30)::DATE AS MONTHQTY FROM TORDER_INFO_ORDER_STAT WHERE CRITDAY BETWEEN TO_CHAR(TO_DATE( #{reqorderday} , 'YYYYMMDD' ) - 30, 'yyyyMMdd') AND TO_CHAR(TO_DATE( #{reqorderday} , 'YYYYMMDD' ), 'yyyyMMdd') GROUP BY OWKEY, CTKEY, ICKEY ) ST ON RE.OWKEY = ST.OWKEY AND RE.CTKEY = ST.CTKEY AND RE.ICKEY = ST.ICKEY LEFT JOIN ( SELECT A.ICKEY
-- AVQTY 가용재고수량 , MAX(CASE WHEN A.CTKEY = '01' THEN COALESCE(A.AVQTY, 0) END) AS AVQTY01 , MAX(CASE WHEN A.CTKEY = '04' THEN COALESCE(A.AVQTY, 0) END) AS AVQTY04 , MAX(CASE WHEN A.CTKEY = '05' THEN COALESCE(A.AVQTY, 0) END) AS AVQTY05 -- PREIBQTY 미입고수량 , MAX(CASE WHEN A.CTKEY = '01' THEN COALESCE(A.PREIBQTY, 0) END) AS PREIBQTY01 , MAX(CASE WHEN A.CTKEY = '04' THEN COALESCE(A.PREIBQTY, 0) END) AS PREIBQTY04 , MAX(CASE WHEN A.CTKEY = '05' THEN COALESCE(A.PREIBQTY, 0) END) AS PREIBQTY05 -- IBEXPCTDAY 입고예정일자 , MAX(CASE WHEN A.CTKEY = '01' THEN A.IBEXPCTDAY END) AS IBEXPCTDAY01 , MAX(CASE WHEN A.CTKEY = '04' THEN A.IBEXPCTDAY END) AS IBEXPCTDAY04 , MAX(CASE WHEN A.CTKEY = '05' THEN A.IBEXPCTDAY END) AS IBEXPCTDAY05 -- IBEXPCTQTY 입고예정수량 , MAX(CASE WHEN A.CTKEY = '01' THEN COALESCE(A.IBEXPCTQTY, 0) END) AS IBEXPCTQTY01 , MAX(CASE WHEN A.CTKEY = '04' THEN COALESCE(A.IBEXPCTQTY, 0) END) AS IBEXPCTQTY04 , MAX(CASE WHEN A.CTKEY = '05' THEN COALESCE(A.IBEXPCTQTY, 0) END) AS IBEXPCTQTY05 -- AVGOBQTY 일평균출고수량 , MAX(CASE WHEN A.CTKEY = '01' THEN COALESCE(A.AVGOBQTY, 0) END) AS AVGOBQTY01 , MAX(CASE WHEN A.CTKEY = '04' THEN COALESCE(A.AVGOBQTY, 0) END) AS AVGOBQTY04 , MAX(CASE WHEN A.CTKEY = '05' THEN COALESCE(A.AVGOBQTY, 0) END) AS AVGOBQTY05 -- B2B 센터재고보장일수
FROM TORDER_INFO_B2BAVGOBQTY_REQORDER A INNER JOIN TORDER_MST_CT B ON A.CTKEY = B.CTKEY WHERE A.CRITDAY = #{reqorderday} GROUP BY A.ICKEY ) B2BINFO ON IC.ICKEY = B2BINFO.ICKEY LEFT JOIN ( SELECT MAX(CASE WHEN CTKEY = '01' THEN COALESCE(GRTIVDAYS, 0) END) AS GRTIVDAYS01 , MAX(CASE WHEN CTKEY = '04' THEN COALESCE(GRTIVDAYS, 0) END) AS GRTIVDAYS04 , MAX(CASE WHEN CTKEY = '05' THEN COALESCE(GRTIVDAYS, 0) END) AS GRTIVDAYS05 -- 리드타임 , MAX(CASE WHEN CTKEY = '01' THEN COALESCE(CTLEADTIME, 0) END) AS CTLEADTIME01 , MAX(CASE WHEN CTKEY = '04' THEN COALESCE(CTLEADTIME, 0) END) AS CTLEADTIME04 , MAX(CASE WHEN CTKEY = '05' THEN COALESCE(CTLEADTIME, 0) END) AS CTLEADTIME05 FROM TORDER_MST_CT ) B2BCON ON 1=1 LEFT JOIN ( SELECT OWKEY , CTKEY , COALESCE(MAX(CASE WHEN REQORDERUNIT = 'CTN' THEN CRITSET END), 0.5) AS CTNCRIT , COALESCE(MAX(CASE WHEN REQORDERUNIT = 'PLT' THEN CRITSET END), 0.5) AS PLTCRIT , COALESCE(MAX(CASE WHEN REQORDERUNIT = 'INN' THEN CRITSET END), 0.5) AS INNCRIT FROM TORDER_MST_REQORDER_CNTRUNIT WHERE OWKEY =#{owkey} AND CTKEY =#{ctkey} AND DELYN ='N' GROUP BY OWKEY, CTKEY ) CRITSET ON RE.OWKEY = CRITSET.OWKEY AND RE.CTKEY = CRITSET.CTKEY LEFT JOIN ( SELECT C.OWKEY,C.CTKEY , D.LCKEY ,C.ICKEY, D.ANSUNGB2BPOCTG, D.NAMSAB2BPOCTG, D.BUSANB2BPOCTG ,D.CBMCLOSRNG FROM TORDER_MST_ICXCT C LEFT JOIN TORDER_MST_LC D ON C.CTKEY = D.CTKEY AND C.LCKEY = D.LCKEY ) LC ON LC.OWKEY= RE.OWKEY AND LC.CTKEY = RE.CTKEY AND LC.ICKEY = RE.ICKEY WHERE IC.POABLEYN = 'Y'
AND RE.REQORDERDAY = #{reqorderday}
AND RE.REQCTKEY = #{reqctkey}
AND RE.REQORDERTYPE = #{reqordertype}
AND RE.URGENCYREQORDERYN = #{urgencyreqorderyn}
AND RE.REQORDERNO = #{reqorderno}
AND RE.REQORDERSTATUS = #{reqorderstatus}
AND #{SEARCH_CONDITION}
AND RE.DLVYREQORDERUNIT = 'PLT'
AND RE.DLVYREQORDERUNIT != 'PLT'
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY RE.UPDATEDATE DESC NULLS LAST, RE.ICKEY ASC
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

/* oms-po-poCnfrm-sql-oracle.xml - selectCheckReqCtkey */
SELECT COUNT(1)
FROM TORDER_INFO_REQORDER
WHERE 1 = 1
  AND REQORDERDAY = #{reqorderday}
  AND REQCTKEY = #{reqctkey}
  AND REQORDERTYPE = #{reqordertype}
  AND URGENCYREQORDERYN = #{urgencyreqorderyn}
  AND REQORDERSTATUS = '02'

/* oms-po-poCnfrm-sql-oracle.xml - selectTOrderNisSoList */
SELECT COUNT(*) CNT
FROM TORDER_INFO_SO_DT
WHERE URGENCYREQPRCSSEQ = #{reqorderno}

/* oms-po-poCnfrm-sql-oracle.xml - selectSendMalList */ SELECT ICKEY AS ICKEY , REQORDERDAY AS CNFRMREQORDERDAY , '01' AS REQORDERDIV , (SELECT COALESCE(MAX(SEQ), 1) FROM TORDER_INTF_MAL_REQORDERCNFRM WHERE CNFRMREQORDERDAY = TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD') AND REQORDERDIV = '02' ) AS SEQ , SUM(CNFRMREQORDERQTY) AS CNFRMREQORDERQTY FROM TORDER_INFO_REQORDER WHERE REQORDERTYPE = '03' -- 이고발주만 AND URGENCYREQORDERYN = 'Y' -- 정기발주 AND REQORDERNO IN
#{ordNo}
GROUP BY ICKEY, REQORDERDAY

/* oms-po-poCnfrm-sql-oracle.xml - selectDbToay */
SELECT CASE WHEN TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD') > #{today}  
			THEN  'Y'
	   ELSE 'N'
	   END AS DATE_YN,
#{today} AS REQORDER_DAY
